import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// Icons SVG Minimalist #003366
const Icons = {
  Edit: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="2"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>,
  Save: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M5 13l4 4L19 7" /></svg>,
  Delete: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#d32f2f" strokeWidth="2"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Add: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M12 4v16m8-8H4" /></svg>
};

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updateStaffInfo } = useData();

  // State
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  const [editMode, setEditMode] = useState(null);
  const [editForm, setEditForm] = useState({});

  // --- PHÂN QUYỀN (PERMISSIONS) ---
  const isChief = user?.role === 'chief';
  const isOp = user?.role === 'op';
  const isReg = user?.role === 'reg';
  
  // Quyền chỉnh sửa: Chief, Op, Reg đều vào được, nhưng quyền hạn khác nhau bên trong
  const canAccessManager = isChief || isOp || isReg;

  // Danh sách Role chức năng (Functional Roles)
  const opFunctionalRoles = ['ST', 'TT', 'CCS', 'CCO', 'CCA'];
  const regFunctionalRoles = ['FFM', 'FFS', 'FFA'];

  if (!canAccessManager) return <div>Bạn không có quyền truy cập trang này.</div>;

  // --- LOGIC XỬ LÝ ---

  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Chỉ Chief Administrator mới được tạo tài khoản!");
    if (!formData.name || !formData.username || !formData.password) return;
    
    addStaff({ 
      ...formData, 
      role: 'staff',      // Mặc định System Role là staff
      positions: [],      // Chưa có Functional Role
      baseUBI: 0,         // Lương định mức
      ubiPercentage: 100, // % hưởng lương
      status: 'active'
    });
    setFormData({ name: '', username: '', password: '' });
  };

  const handleDelete = (id) => {
    if (!isChief) return alert("Chỉ Chief Administrator mới được xóa tài khoản!");
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) deleteStaff(id);
  };

  const startEdit = (staff) => {
    // Logic chặn: Op/Reg không được sửa Chief (trừ khi chính là họ)
    if (staff.role === 'chief' && !isChief && user.id !== staff.id) {
        return alert("Bạn không có quyền chỉnh sửa thông tin của Chief Admin.");
    }

    setEditMode(staff.id);
    setEditForm({
      name: staff.name,
      phone: staff.phone || '',
      email: staff.email || '',
      department: staff.department || '',
      title: staff.title || '',
      role: staff.role || 'staff',
      positions: staff.positions || [],
      baseUBI: staff.baseUBI || 0,
      ubiPercentage: staff.ubiPercentage || 100,
      status: staff.status || 'active'
    });
  };

  const handlePositionToggle = (pos) => {
    const currentPositions = editForm.positions || [];
    if (currentPositions.includes(pos)) {
      setEditForm({ ...editForm, positions: currentPositions.filter(p => p !== pos) });
    } else {
      setEditForm({ ...editForm, positions: [...currentPositions, pos] });
    }
  };

  const saveEdit = (id) => {
    updateStaffInfo(id, editForm);
    setEditMode(null);
    alert("Cập nhật thông tin thành công!");
  };

  // Helper hiển thị tên System Role
  const systemRoleName = (r) => {
    switch(r) {
        case 'chief': return 'Chief Admin';
        case 'reg': return 'Regulatory Admin';
        case 'op': return 'Operational Admin';
        default: return 'Staff';
    }
  };

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #003366', paddingBottom: '10px', marginTop: 0 }}>Quản lý & Phân quyền Nhân sự</h2>

      {/* Form thêm mới (Chỉ Chief thấy) */}
      {isChief && (
        <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 15px 0', color: '#003366' }}>+ Thêm nhân sự mới</h4>
          <form onSubmit={handleAdd} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required style={styles.input} />
            <input placeholder="Username" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} required style={styles.input} />
            <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} required style={styles.input} />
            <button type="submit" style={styles.btnAdd}><Icons.Add /> Tạo tài khoản</button>
          </form>
        </div>
      )}

      {/* Danh sách nhân sự */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
        {staffList.map(staff => (
          <div key={staff.id} style={{ 
              background: 'white', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', padding: '20px', 
              border: editMode === staff.id ? '2px solid #003366' : '1px solid #eee',
              opacity: (staff.status === 'suspended' && editMode !== staff.id) ? 0.6 : 1
          }}>
            
            {/* --- HEADER CARD --- */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '15px' }}>
              <div>
                <strong style={{ fontSize: '1.1rem', color: '#333' }}>{staff.name}</strong>
                <div style={{ fontSize: '0.85rem', color: '#666' }}>@{staff.username}</div>
              </div>
              <span style={{ 
                background: staff.role === 'chief' ? '#003366' : (staff.role === 'staff' ? '#f0f2f5' : '#e6f7ff'), 
                color: staff.role === 'chief' ? 'white' : '#003366',
                padding: '4px 8px', borderRadius: '4px', fontSize: '0.7rem', fontWeight: 'bold', textTransform: 'uppercase'
              }}>
                {systemRoleName(staff.role)}
              </span>
            </div>

            {/* --- BODY CARD --- */}
            {editMode === staff.id ? (
              // >>> CHẾ ĐỘ CHỈNH SỬA (EDIT MODE)
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                
                {/* 1. Thông tin liên hệ */}
                <div style={styles.group}>
                  <label style={styles.label}>Thông tin cá nhân</label>
                  <input value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} placeholder="Họ tên" style={styles.inputFull} />
                  <div style={{display: 'flex', gap: '5px'}}>
                    <input value={editForm.phone} onChange={e => setEditForm({...editForm, phone: e.target.value})} placeholder="SĐT" style={styles.inputFull} />
                    <input value={editForm.email} onChange={e => setEditForm({...editForm, email: e.target.value})} placeholder="Email" style={styles.inputFull} />
                  </div>
                  <div style={{display: 'flex', gap: '5px'}}>
                    <input value={editForm.department} onChange={e => setEditForm({...editForm, department: e.target.value})} placeholder="Phòng ban" style={styles.inputFull} />
                    <input value={editForm.title} onChange={e => setEditForm({...editForm, title: e.target.value})} placeholder="Chức danh" style={styles.inputFull} />
                  </div>
                </div>

                {/* 2. System Role (Chỉ Chief được sửa) */}
                {isChief && (
                  <div style={styles.group}>
                    <label style={styles.label}>System Role (Quyền quản trị)</label>
                    <select value={editForm.role} onChange={e => setEditForm({...editForm, role: e.target.value})} style={styles.inputFull}>
                      <option value="staff">Staff (Nhân viên)</option>
                      <option value="op">Operational Manager</option>
                      <option value="reg">Regulatory Manager</option>
                      <option value="chief">Chief Administrator</option>
                    </select>
                  </div>
                )}

                {/* 3. Functional Roles (Xét vị trí) */}
                {(isChief || isOp || isReg) && (
                   <div style={styles.group}>
                     <label style={styles.label}>Xét vị trí (Functional Roles)</label>
                     <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                        {/* Nhóm OP Roles: ST, TT, CCS... (Chief hoặc Op thấy) */}
                        {(isChief || isOp) && opFunctionalRoles.map(r => (
                          <label key={r} style={styles.checkboxLabel}>
                            <input type="checkbox" 
                              checked={editForm.positions?.includes(r)} 
                              onChange={() => handlePositionToggle(r)} 
                            /> {r}
                          </label>
                        ))}
                        {/* Nhóm REG Roles: FFM, FFS... (Chief hoặc Reg thấy) */}
                        {(isChief || isReg) && regFunctionalRoles.map(r => (
                          <label key={r} style={styles.checkboxLabel}>
                            <input type="checkbox" 
                              checked={editForm.positions?.includes(r)} 
                              onChange={() => handlePositionToggle(r)} 
                            /> {r}
                          </label>
                        ))}
                     </div>
                   </div>
                )}

                {/* 4. Tài chính UBI (Chỉ Chief được sửa) */}
                {isChief && (
                  <div style={styles.group}>
                    <label style={styles.label}>Mức lương & UBI</label>
                    <div style={{display: 'flex', gap: '5px', alignItems: 'center'}}>
                       <input 
                         type="number" 
                         value={editForm.baseUBI} 
                         onChange={e => setEditForm({...editForm, baseUBI: Number(e.target.value)})} 
                         placeholder="UBI Định mức" 
                         style={styles.inputFull} 
                       />
                       <select 
                         value={editForm.ubiPercentage} 
                         onChange={e => setEditForm({...editForm, ubiPercentage: Number(e.target.value)})} 
                         style={{...styles.inputFull, width: '100px'}}
                       >
                         <option value={25}>25%</option>
                         <option value={50}>50%</option>
                         <option value={75}>75%</option>
                         <option value={100}>100%</option>
                       </select>
                    </div>
                    <small style={{color: '#666', fontStyle: 'italic', display: 'block', marginTop: '4px'}}>
                        Thực lĩnh: <span style={{color: '#003366', fontWeight: 'bold'}}>{((editForm.baseUBI * editForm.ubiPercentage)/100).toLocaleString()} VNĐ</span>
                    </small>
                  </div>
                )}

                {/* 5. Trạng thái (Chỉ Chief hoặc Reg/Op quản lý nếu cần thiết - ở đây để Chief) */}
                {isChief && (
                    <div style={styles.group}>
                        <label style={styles.label}>Trạng thái tài khoản</label>
                        <select value={editForm.status} onChange={e => setEditForm({...editForm, status: e.target.value})} style={styles.inputFull}>
                            <option value="active">Đang hoạt động</option>
                            <option value="suspended">Đình chỉ</option>
                        </select>
                    </div>
                )}

                {/* Nút Action */}
                <div style={{ display: 'flex', gap: '10px', marginTop: '5px' }}>
                  <button onClick={() => saveEdit(staff.id)} style={styles.btnSave}>
                    <Icons.Save /> Cập nhật mới
                  </button>
                  <button onClick={() => setEditMode(null)} style={styles.btnCancel}>Hủy</button>
                </div>
              </div>
            ) : (
              // >>> CHẾ ĐỘ XEM (VIEW MODE)
              <div style={{ display: 'flex', flexDirection: 'column', height: '100%', justifyContent: 'space-between' }}>
                <div>
                   {/* Hiển thị Roles */}
                   {(staff.positions && staff.positions.length > 0) ? (
                     <div style={{ marginBottom: '10px' }}>
                       <div style={{ fontSize: '0.7rem', color: '#999', textTransform: 'uppercase', marginBottom: '4px' }}>Functional Roles</div>
                       <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                         {staff.positions.map(p => (
                           <span key={p} style={{ background: '#333', color: '#fff', padding: '2px 6px', borderRadius: '3px', fontSize: '0.7rem' }}>{p}</span>
                         ))}
                       </div>
                     </div>
                   ) : <div style={{ fontSize: '0.8rem', color: '#999', fontStyle: 'italic', marginBottom: '10px' }}>Chưa xét vị trí</div>}
                   
                   {/* Hiển thị Lương (Chỉ Chief thấy) */}
                   {isChief && (
                     <div style={{ marginBottom: '10px', padding: '8px', background: '#f8f9fa', borderRadius: '4px', border: '1px dashed #ccc' }}>
                       <div style={{ fontSize: '0.7rem', color: '#666' }}>UBI (Định mức / Thực tế):</div>
                       <strong style={{ color: '#28a745' }}>
                         {(staff.baseUBI || 0).toLocaleString()} / {((staff.baseUBI * (staff.ubiPercentage || 0))/100).toLocaleString()}
                       </strong>
                       <span style={{ fontSize: '0.7rem', marginLeft: '5px', color: '#666' }}>({staff.ubiPercentage}%)</span>
                     </div>
                   )}

                   {/* Thông tin phụ */}
                   <div style={{ fontSize: '0.85rem', color: '#555' }}>
                      {staff.phone && <div>📞 {staff.phone}</div>}
                      {staff.email && <div>✉️ {staff.email}</div>}
                      {staff.status === 'suspended' && <div style={{color: 'red', fontWeight: 'bold', marginTop: '5px'}}>⚠ ĐÃ ĐÌNH CHỈ</div>}
                   </div>
                </div>

                {/* Nút Action View Mode */}
                <div style={{ borderTop: '1px solid #eee', paddingTop: '10px', marginTop: '15px', display: 'flex', justifyContent: 'flex-end', gap: '8px' }}>
                   {/* Nút sửa hiển thị cho người có quyền */}
                   {canAccessManager && (
                     <button onClick={() => startEdit(staff)} style={styles.btnEdit} title="Điều chỉnh thông tin">
                       <Icons.Edit /> Điều chỉnh
                     </button>
                   )}
                   {/* Nút xóa chỉ Chief */}
                   {isChief && (
                     <button onClick={() => handleDelete(staff.id)} style={styles.btnDelete} title="Xóa nhân sự">
                       <Icons.Delete />
                     </button>
                   )}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

