    checkboxLabel: { display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.8rem', background: 'white', padding: '4px 8px', borderRadius: '4px', border: '1px solid #ddd', cursor: 'pointer' },
    btnAdd: { background: '#28a745', color: 'white', border: 'none', borderRadius: '4px', padding: '8px 15px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' },
    btnSave: { background: '#003366', color: 'white', border: 'none', borderRadius: '4px', padding: '8px', cursor: 'pointer', flex: 1, display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '5px', fontWeight: 'bold' },
    btnCancel: { background: '#6c757d', color: 'white', border: 'none', borderRadius: '4px', padding: '8px 15px', cursor: 'pointer' },
    btnEdit: { background: 'white', border: '1px solid #003366', color: '#003366', borderRadius: '4px', padding: '6px 12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.85rem' },
    btnDelete: { background: '#ffebee', border: '1px solid #ffcdd2', color: '#d32f2f', borderRadius: '4px', padding: '6px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center' }
